class Solution {
public:
    int minSwaps(string s) {
        int count = 0, res = 0;
        for (char c : s) {
            if (c == '[') {
                count++;
            } else {
                count--;
                if (count < 0) {
                    res++;
                    count = 0;
                }
            }
        }
        return res;
    }
};
```
